+
+	for _, eventType := range EventTypes {
+		overrideEntries := override.GetEntries(eventType)
+		if len(overrideEntries) == 0 {
+			continue
+		}
+
+		baseEntries := result.GetEntries(eventType)
+		if baseEntries == nil {
+			baseEntries = []HookEntry{}
+		}
+
+		for _, oe := range overrideEntries {
